class Solution:
    def shortestBeautifulSubstring(self, s, k):
        n = len(s)
        candidates = []
        for i in range(n):
            ones = 0
            for j in range(i, n):
                if s[j] == '1':
                    ones += 1
                if ones == k:
                    candidates.append(s[i:j+1])
                elif ones > k:
                    break
        if not candidates:
            return ""
        min_len = min(len(c) for c in candidates)
        best = [c for c in candidates if len(c) == min_len]
        return min(best)

