class Solution:
    def shortestBeautifulSubstring(self, s: str, k: int) -> str:
        n = len(s)
        for length in range(k, n + 1):
            found = []
            for i in range(0, n - length + 1):
                sub = s[i:i+length]
                if sub.count('1') == k:
                    found.append(sub)
            if found:
                return min(found)
        return ""

