var shortestBeautifulSubstring = function(s, k) {
    const n = s.length;
    for (let length = k; length <= n; length++) {
        const found = [];
        for (let i = 0; i + length <= n; i++) {
            const sub = s.substring(i, i + length);
            let ones = 0;
            for (let c = 0; c < sub.length; c++) {
                if (sub[c] === '1') ones++;
            }
            if (ones === k) found.push(sub);
        }
        if (found.length > 0) {
            found.sort();
            return found[0];
        }
    }
    return "";
};
